  1	import { Rule } from '@openshift-console/dynamic-plugin-sdk';
  2	import { Alert, Card, CardBody, Flex, FlexItem, Grid, GridItem, Text, TextVariants } from '@patternfly/react-core';
  3	import { AngleDownIcon, AngleRightIcon } from '@patternfly/react-icons';
  4	import * as React from 'react';
  5	import { useTranslation } from 'react-i18next';
  6	import { localStorageHealthSummaryExpandedKey, useLocalStorage } from '../../utils/local-storage-hook';
  7	import { HealthStats } from './health-helper';
  8	import { HealthMetricCard } from './health-metric-card';
  9	
 10	type StatusClass = 'success' | 'critical' | 'warning' | 'info';
 11	
 12	export interface HealthSummaryProps {
 13	  rules: Rule[];
 14	  stats: HealthStats;
 15	  forceCollapsed?: boolean;
 16	}
 17	
 18	export const HealthSummary: React.FC<HealthSummaryProps> = ({ rules, stats, forceCollapsed }) => {
 19	  const { t } = useTranslation('plugin__netobserv-plugin');
 20	  const [isExpanded, setIsExpanded] = useLocalStorage<boolean>(localStorageHealthSummaryExpandedKey, false);
 21	
 22	  // Determine the actual display state: forced collapsed or user's preference
 23	  const displayExpanded = forceCollapsed ? false : isExpanded;
 24	
 25	  // Helper function to format metric details
 26	  const formatMetricDetail = (firingAlerts: number, recordingRules: number): string => {
 27	    const parts = [];
 28	    if (firingAlerts > 0) {
 29	      parts.push(t('{{count}} alerts', { count: firingAlerts }));
 30	    }
 31	    if (recordingRules > 0) {
 32	      parts.push(t('{{count}} recording rules', { count: recordingRules }));
 33	    }
 34	    return parts.join(', ');
 35	  };
 36	
 37	  // Count recording rules by severity
 38	  let recordingRulesCritical = 0;
 39	  let recordingRulesWarning = 0;
 40	  let recordingRulesInfo = 0;
 41	
 42	  // Count from global
 43	  recordingRulesCritical += stats.global.critical.recording.length;
 44	  recordingRulesWarning += stats.global.warning.recording.length;
 45	  recordingRulesInfo += stats.global.other.recording.length;
 46	
 47	  // Count from all namespaces
 48	  stats.byNamespace.forEach(ns => {
 49	    recordingRulesCritical += ns.critical.recording.length;
 50	    recordingRulesWarning += ns.warning.recording.length;
 51	    recordingRulesInfo += ns.other.recording.length;
 52	  });
 53	
 54	  // Count from all nodes
 55	  stats.byNode.forEach(node => {
 56	    recordingRulesCritical += node.critical.recording.length;
 57	    recordingRulesWarning += node.warning.recording.length;
 58	    recordingRulesInfo += node.other.recording.length;
 59	  });
 60	
 61	  // Count from all owners (workloads)
 62	  stats.byOwner.forEach(owner => {
 63	    recordingRulesCritical += owner.critical.recording.length;
 64	    recordingRulesWarning += owner.warning.recording.length;
 65	    recordingRulesInfo += owner.other.recording.length;
 66	  });
 67	
 68	  // Check if there are no rules at all (neither alerts nor recording rules)
 69	  const totalRecordingRules = recordingRulesCritical + recordingRulesWarning + recordingRulesInfo;
 70	  if (rules.length === 0 && totalRecordingRules === 0) {
 71	    return (
 72	      <div className="health-summary-dashboard">
 73	        <Alert title={t('No rules found, health cannot be determined')} variant="info">
 74	          <>
 75	            {t(
 76	              'Check alert definitions in FlowCollector "spec.processor.metrics.alertGroups" and "spec.processor.metrics.disableAlerts".'
 77	            )}
 78	            <br />
 79	            {t('Make sure that Prometheus and AlertManager are running.')}
 80	          </>
 81	        </Alert>
 82	      </div>
 83	    );
 84	  }
 85	
 86	  const summaryStats = {
 87	    critical: {
 88	      firingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'firing' && a.labels.severity === 'critical')
 89	        .length,
 90	      firingRules: rules.filter(a => a.state === 'firing' && a.labels.severity === 'critical').length,
 91	      pendingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'pending' && a.labels.severity === 'critical')
 92	        .length,
 93	      pendingRules: rules.filter(a => a.state === 'pending' && a.labels.severity === 'critical').length,
 94	      recordingRules: recordingRulesCritical,
 95	      total: rules.filter(a => a.labels.severity === 'critical').length
 96	    },
 97	    warning: {
 98	      firingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'firing' && a.labels.severity === 'warning')
 99	        .length,
100	      firingRules: rules.filter(a => a.state === 'firing' && a.labels.severity === 'warning').length,
101	      pendingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'pending' && a.labels.severity === 'warning')
102	        .length,
103	      pendingRules: rules.filter(a => a.state === 'pending' && a.labels.severity === 'warning').length,
104	      recordingRules: recordingRulesWarning,
105	      total: rules.filter(a => a.labels.severity === 'warning').length
106	    },
107	    info: {
108	      firingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'firing' && a.labels.severity === 'info')
109	        .length,
110	      firingRules: rules.filter(a => a.state === 'firing' && a.labels.severity === 'info').length,
111	      pendingAlerts: rules.flatMap(r => r.alerts).filter(a => a.state === 'pending' && a.labels.severity === 'info')
112	        .length,
113	      pendingRules: rules.filter(a => a.state === 'pending' && a.labels.severity === 'info').length,
114	      recordingRules: recordingRulesInfo,
115	      total: rules.filter(a => a.labels.severity === 'info').length
116	    }
117	  };
118	
119	  let title = t('The network looks healthy');
120	  let statusClass: StatusClass = 'success';
121	  if (summaryStats.critical.firingAlerts > 0 || summaryStats.critical.recordingRules > 0) {
122	    statusClass = 'critical';
123	    title = t('There are critical network issues');
124	  } else if (summaryStats.warning.firingAlerts > 0 || summaryStats.warning.recordingRules > 0) {
125	    statusClass = 'warning';
126	    title = t('There are network warnings');
127	  } else if (summaryStats.info.firingAlerts > 0 || summaryStats.info.recordingRules > 0) {
128	    statusClass = 'info';
129	    title = t('The network looks relatively healthy, with minor issues');
130	  }
131	
132	  const criticalTotal = summaryStats.critical.firingAlerts + summaryStats.critical.recordingRules;
133	  const warningTotal = summaryStats.warning.firingAlerts + summaryStats.warning.recordingRules;
134	  const infoTotal = summaryStats.info.firingAlerts + summaryStats.info.recordingRules;
135	
136	  // Build details like the old Alert summary
137	  const hasViolations = criticalTotal > 0 || warningTotal > 0 || infoTotal > 0;
138	  const details: string[] = [];
139	
140	  // Critical
141	  if (summaryStats.critical.firingAlerts > 0 || summaryStats.critical.recordingRules > 0) {
142	    const total = summaryStats.critical.firingAlerts + summaryStats.critical.recordingRules;
143	    const parts = [];
144	    if (summaryStats.critical.firingAlerts > 0) {
145	      parts.push(t('{{count}} from alerts', { count: summaryStats.critical.firingAlerts }));
146	    }
147	    if (summaryStats.critical.recordingRules > 0) {
148	      parts.push(t('{{count}} from recording rules', { count: summaryStats.critical.recordingRules }));
149	    }
150	    details.push(t('{{total}} critical issues ({{breakdown}})', { total, breakdown: parts.join(', ') }));
151	  } else if (summaryStats.critical.pendingAlerts > 0) {
152	    details.push(
153	      t('{{pendingAlerts}} pending critical issues, from {{pendingRules}} distinct rules', summaryStats.critical)
154	    );
155	  } else if (!hasViolations) {
156	    details.push(t('No critical issues out of {{total}} rules', summaryStats.critical));
157	  }
158	
159	  // Warning
160	  if (summaryStats.warning.firingAlerts > 0 || summaryStats.warning.recordingRules > 0) {
161	    const total = summaryStats.warning.firingAlerts + summaryStats.warning.recordingRules;
162	    const parts = [];
163	    if (summaryStats.warning.firingAlerts > 0) {
164	      parts.push(t('{{count}} from alerts', { count: summaryStats.warning.firingAlerts }));
165	    }
166	    if (summaryStats.warning.recordingRules > 0) {
167	      parts.push(t('{{count}} from recording rules', { count: summaryStats.warning.recordingRules }));
168	    }
169	    details.push(t('{{total}} warnings ({{breakdown}})', { total, breakdown: parts.join(', ') }));
170	  } else if (summaryStats.warning.pendingAlerts > 0) {
171	    details.push(t('{{pendingAlerts}} pending warnings, from {{pendingRules}} distinct rules', summaryStats.warning));
172	  } else if (!hasViolations) {
173	    details.push(t('No warnings out of {{total}} rules', summaryStats.warning));
174	  }
175	
176	  // Info
177	  if (summaryStats.info.firingAlerts > 0 || summaryStats.info.recordingRules > 0) {
178	    const total = summaryStats.info.firingAlerts + summaryStats.info.recordingRules;
179	    const parts = [];
180	    if (summaryStats.info.firingAlerts > 0) {
181	      parts.push(t('{{count}} from alerts', { count: summaryStats.info.firingAlerts }));
182	    }
183	    if (summaryStats.info.recordingRules > 0) {
184	      parts.push(t('{{count}} from recording rules', { count: summaryStats.info.recordingRules }));
185	    }
186	    details.push(t('{{total}} minor issues ({{breakdown}})', { total, breakdown: parts.join(', ') }));
187	  } else if (summaryStats.info.pendingAlerts > 0) {
188	    details.push(t('{{pendingAlerts}} pending minor issues, from {{pendingRules}} distinct rules', summaryStats.info));
189	  } else if (!hasViolations) {
190	    details.push(t('No minor issues out of {{total}} rules', summaryStats.info));
191	  }
192	
193	  const handleToggle = () => {
194	    // Skip toggle when forced collapsed
195	    if (forceCollapsed) {
196	      return;
197	    }
198	    setIsExpanded(!isExpanded);
199	  };
200	
201	  const handleKeyDown = (e: React.KeyboardEvent) => {
202	    if (e.key === 'Enter' || e.key === ' ') {
203	      e.preventDefault();
204	      handleToggle();
205	    }
206	  };
207	
208	  return (
209	    <Flex
210	      gap={{ default: 'gapMd' }}
211	      alignItems={{ default: 'alignItemsCenter' }}
212	      className={`health-summary-dashboard ${forceCollapsed ? 'force-collapsed' : ''}`}
213	      onClick={handleToggle}
214	      onKeyDown={handleKeyDown}
215	      tabIndex={forceCollapsed ? -1 : 0}
216	      role="button"
217	      aria-label={displayExpanded ? t('Collapse health summary') : t('Expand health summary')}
218	      aria-expanded={displayExpanded}
219	      aria-disabled={forceCollapsed}
220	      style={{ cursor: forceCollapsed ? 'default' : 'pointer' }}
221	    >
222	      {!forceCollapsed && (
223	        <FlexItem className="health-summary-toggle-icon">
224	          {displayExpanded ? <AngleDownIcon /> : <AngleRightIcon />}
225	        </FlexItem>
226	      )}
227	      <FlexItem flex={{ default: 'flex_1' }}>
228	        {displayExpanded ? (
229	          <Grid hasGutter>
230	            {/* Status card */}
231	            <GridItem lg={6} md={6} sm={12}>
232	              <Card className={`health-metric-card status ${statusClass}`}>
233	                <CardBody>
234	                  <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsNone' }}>
235	                    <FlexItem>
236	                      <Text component={TextVariants.small} className="metric-label">
237	                        {t('Status')}
238	                      </Text>
239	                    </FlexItem>
240	                    <FlexItem>
241	                      <Text component={TextVariants.p} className="metric-status">
242	                        {title}
243	                      </Text>
244	                    </FlexItem>
245	                    {details.length > 0 && (
246	                      <FlexItem className="status-details">
247	                        <ul>
248	                          {details.map((text, i) => (
249	                            <li key={'li_' + i}>{text}</li>
250	                          ))}
251	                        </ul>
252	                      </FlexItem>
253	                    )}
254	                  </Flex>
255	                </CardBody>
256	              </Card>
257	            </GridItem>
258	
259	            {/* Critical card */}
260	            <GridItem lg={2} md={6} sm={12}>
261	              <HealthMetricCard
262	                severity="critical"
263	                label={t('Critical')}
264	                total={criticalTotal}
265	                detail={
266	                  criticalTotal > 0
267	                    ? formatMetricDetail(summaryStats.critical.firingAlerts, summaryStats.critical.recordingRules)
268	                    : undefined
269	                }
270	              />
271	            </GridItem>
272	
273	            {/* Warning card */}
274	            <GridItem lg={2} md={6} sm={12}>
275	              <HealthMetricCard
276	                severity="warning"
277	                label={t('Warning')}
278	                total={warningTotal}
279	                detail={
280	                  warningTotal > 0
281	                    ? formatMetricDetail(summaryStats.warning.firingAlerts, summaryStats.warning.recordingRules)
282	                    : undefined
283	                }
284	              />
285	            </GridItem>
286	
287	            {/* Info card */}
288	            <GridItem lg={2} md={6} sm={12}>
289	              <HealthMetricCard
290	                severity="info"
291	                label={t('Info')}
292	                total={infoTotal}
293	                detail={
294	                  infoTotal > 0
295	                    ? formatMetricDetail(summaryStats.info.firingAlerts, summaryStats.info.recordingRules)
296	                    : undefined
297	                }
298	              />
299	            </GridItem>
300	          </Grid>
301	        ) : (
302	          <Flex gap={{ default: 'gapSm' }} alignItems={{ default: 'alignItemsCenter' }}>
303	            {/* Collapsed view - just counters with icons */}
304	            <FlexItem className={`health-summary-compact-item ${statusClass}`}>
305	              <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }}>
306	                <FlexItem className="health-summary-compact-icon status" />
307	                <FlexItem>
308	                  <Text component={TextVariants.p} className="health-summary-compact-text">
309	                    {title}
310	                  </Text>
311	                </FlexItem>
312	              </Flex>
313	            </FlexItem>
314	            <FlexItem className="health-summary-compact-item critical">
315	              <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }}>
316	                <FlexItem className="health-summary-compact-icon critical" />
317	                <FlexItem>
318	                  <Text component={TextVariants.p} className="health-summary-compact-text">
319	                    {criticalTotal}
320	                  </Text>
321	                </FlexItem>
322	              </Flex>
323	            </FlexItem>
324	            <FlexItem className="health-summary-compact-item warning">
325	              <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }}>
326	                <FlexItem className="health-summary-compact-icon warning" />
327	                <FlexItem>
328	                  <Text component={TextVariants.p} className="health-summary-compact-text">
329	                    {warningTotal}
330	                  </Text>
331	                </FlexItem>
332	              </Flex>
333	            </FlexItem>
334	            <FlexItem className="health-summary-compact-item info">
335	              <Flex gap={{ default: 'gapXs' }} alignItems={{ default: 'alignItemsCenter' }}>
336	                <FlexItem className="health-summary-compact-icon info" />
337	                <FlexItem>
338	                  <Text component={TextVariants.p} className="health-summary-compact-text">
339	                    {infoTotal}
340	                  </Text>
341	                </FlexItem>
342	              </Flex>
343	            </FlexItem>
344	          </Flex>
345	        )}
346	      </FlexItem>
347	    </Flex>
348	  );
349	};

